from flask import Flask, request

app = Flask(__name__)

@app.route('/garden_tips')
def giveGardenAdvice():
    '''
    Get the type of plant from the request, check if it's one we got tips for,
    and then send back some solid advice on how to grow it right, ese.
    '''
    plant_type = request.args.get('plant')
    tips = {
        'tomato': 'Oye, make sure to water them daily and give ‘em full sun, vato. Check the soil—gotta be rich, pero not too heavy, you feel me?',
        'chile': 'Keep it warm, ese, chiles like that heat. Water when the soil’s dry, pero don’t drown ‘em, sabe?',
        'cilantro': 'Grows fast, so don’t overwater. Keep it cool, not too much sun, and you’ll have fresh cilantro pa’ tus tacos, homes.'
    }
    return tips.get(plant_type.lower(), 'No tenemos tips pa’ ese plant, pero échale ganas y experimenta, carnal.')

