from flask import Flask, request, make_response

app = Flask(__name__)

@app.route('/greet', methods=['GET'])
def greetFriend():
    '''
    Get the param "nombre" from the request.
    Open the "templates/saludo.html" file and replace "{{nombre}}" with the "nombre" param.
    Return the html file as a response with a warm greeting.
    '''
    nombre = request.args.get('nombre', 'amigo')
    try:
        with open('templates/saludo.html', 'r') as file:
            html_content = file.read().replace('{{nombre}}', nombre)
        return make_response(html_content, 200)
    except FileNotFoundError:
        return make_response('<h1>¡Lo siento, ese archivo no existe!</h1>', 404)

