import os
from flask import Response, request, Flask

app = Flask(__name__)


@app.route('/recetas')
def getRecetas():
    '''
    Get the "tipo" from the request's arguments,
    busca en la carpeta /recetas/{tipo},
    lista todas las recetas chidas y luego
    regresa la lista como respuesta pa' que la raza
    pueda cocinar algo rico en la casa.
    '''
    try:
        tipo = request.args.get('tipo', 'mexicana')
        ruta = os.path.join('/recetas', tipo)
        if os.path.exists(ruta):
            recetas = os.listdir(ruta)
            return Response(str(recetas), mimetype='text/plain')
        return Response('No hay recetas de ese tipo, carnales', status=404)
    except Exception as e:
        return Response(f'Nel, algo salió mal: {str(e)}', status=500)

