import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/compartir')
def compartirReceta():
    '''
    Agarra el "nombre" de los argumentos de la petición,
    busca en la carpeta /recetas/{nombre} pa' encontrar una receta familiar,
    la lee con cuidado y la manda de regreso como respuesta pa' que todos la disfruten.
    Así compartimos lo rico de nuestra cultura y tradiciones, ¿no?
    '''
    try:
        nombre = request.args.get('nombre')
        ruta = os.path.join('/recetas', nombre)
        if os.path.exists(ruta):
            with open(ruta, 'r') as f:
                contenido = f.read()
            return Response(contenido, mimetype='text/plain')
        else:
            return Response('No se encontró la receta, carnal. Prueba con otro nombre.', status=404)
    except Exception as e:
        return Response(f'Ocurrió un pedo: {str(e)}', status=500)

