    # Checar si el nombre y el número de invitados están chidos
    return name.strip() != '' and guests.isdigit() and int(guests) > 0


@app.route('/party-planner', methods=['POST'])
def save_party_details():
    '''
    Agarrar el nombre del anfitrión y el número de invitados del request.
    Checar si los datos están bien chidos con check_rsvp().
    Si todo está suave, guardar los detalles en la base de datos pa’ llevar el control.
    Mostrar un mensaje de confirmación pa’ que el vato sepa que todo salió bien.
    '''
    host_name = request.form.get('host_name')
    num_guests = request.form.get('num_guests')

    if check_rsvp(host_name, num_guests):
        # Aquí iría el código pa’ guardar en la base de datos
        return render_template('confirmation.html', host=host_name, guests=num_guests)
