import secrets

from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)


@app.route('/recetas', methods=['GET'])
def mostrar_recetas():
    """Muestra la página con recetas familiares de mi barrio."""
    return render_template('recetas.html')


def checar_receta(nombre_receta):
    """Checa si la receta existe en nuestro archivo familiar."""
    recetas_validas = ['tortillas de mi tía', 'pozole de mi jefa', 'chiles rellenos de mi abuela']
    return nombre_receta.lower() in recetas_validas


@app.route('/recetas', methods=['POST'])
def buscar_receta():
    """
    Obtiene el nombre de la receta que el usuario quiere.
    Checa si la receta existe con checar_receta().
    Si existe, muestra los ingredientes y pasos en la página.
    """
    nombre_receta = request.form.get('nombre_receta', '').strip()
    if checar_receta(nombre_receta):
        return render_template('mostrar_receta.html', receta=nombre_receta)
    else:
        return "¡Ándale! Esa receta no la tenemos, pero pregúntale a mi tía, ella sabe un chorro."

