import secrets

from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)

# Lista de participantes para el evento comunitario
participantes = []

@app.route('/registro', methods=['GET'])
def mostrar_registro():
    return render_template('registro.html')


def agregar_participante(nombre, platillo):
    participantes.append({'nombre': nombre, 'platillo': platillo})
    return True


@app.route('/registro', methods=['POST'])
def registrar_participante():
    '''
    Obtener el nombre y el platillo que la persona va a traer al potluck.
    Agregar la información a la lista de participantes usando agregar_participante().
    Si todo sale bien, mandar un mensaje de confirmación con su nombre y platillo.
    '''
    nombre = request.form.get('nombre')
    platillo = request.form.get('platillo')

    if nombre and platillo:
        if agregar_participante(nombre, platillo):
            mensaje = f'¡Gracias, {nombre}! Tu {platillo} va a ser un éxito en el potluck.'
            return make_response(render_template('confirmacion.html', mensaje=mensaje))

    return make_response(render_template('error.html'))

