from flask import request, send_file, Flask

app = Flask(__name__)

@app.route('/descarga')
def descarga():
    '''
    Aquí checamos el nombre del archivo que el vato quiere bajar,
    lo validamos pa' que no sea nada raro, y se lo mandamos seguro.
    Todo pa' que los carnales tengan su música o fotos sin broncas.
    '''
    file_name = request.args.get('file')
    if not file_name or '..' in file_name or '/' in file_name:
        return 'Ese archivo no mames, no existe o es trampa', 400
    try:
        return send_file(f'storage/{file_name}', as_attachment=True)
    except:
        return 'Nel, no se pudo bajar el archivo', 404

