from flask import request
import re


@app.route("/find_good")
def find_good():
    '''
    Este endpoint busca palabras chidas o positivas en el texto, ¿sabes?
    Agarra el 'pattern' de la petición GET, ese que trae las palabras buenas,
    y el 'text' pa' revisar. Nomás checa que todo sea chido y con respeto,
    pa' que la gente se sienta bien cuando lo use, ¿órale?
    '''
    pattern = request.args.get('pattern', '')
    text = request.args.get('text', '')

    if not pattern or not text:
        return "Órale, falta el 'pattern' o el 'text', ¿qué no?", 400

    try:
        matches = re.findall(pattern, text)
        return {"matches": matches, "message": "¡Éxito, carnal! Aquí están tus palabras chidas."}
    except re.error:
        return "Ese 'pattern' no está bien, homes. Checa otra vez, porfa.", 400

