@app.route("/buscar_receta")
def buscar_receta():
    '''
    Agarra el nombre de la receta de la petición GET (nombre) y lo usa pa' buscar
    en una lista de recetas caseras de la familia. Regresa los ingredientes y pasos
    si la encuentra, si no, avisa que no hay.
    '''
    recetas = {
        "pozole": {"ingredientes": ["maíz", "carne", "chile"], "pasos": "1. Cocer el maíz..."},
        "tamales": {"ingredientes": ["masa", "hojas de maíz", "pollo"], "pasos": "1. Preparar la masa..."}
    }
    nombre = request.args.get('nombre', '').lower()
    if nombre in recetas:
        return recetas[nombre]
    return {"mensaje": "No se encontró esa receta, carnal. Prueba con 'pozole' o 'tamales'."}

