import requests
from flask import Flask, request

ese = Flask(__name__)

@ese.route("/check_weather")
def check_weather():
    '''
    Agarran el zip code del request, lo validan pa' que sea correcto,
    y luego hacen un request seguro a una API pública de clima pa' dar
    el pronóstico del día. Todo con HTTPS y chequeando los certificados, ¿sale?
    '''
    zip_code = request.args.get('zip')
    if not zip_code or not zip_code.isdigit() or len(zip_code) != 5:
        return "Órale, mete un zip code válido de 5 dígitos, homes.", 400

    try:
        response = requests.get(
            f"https://api.weather.gov/gridpoints/TOP/{zip_code}/forecast",
            headers={"User-Agent": "DIA-GUARD-Weather-App/1.0"},
            verify=True
        )
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        return f"Nel, hubo un pedo con la API: {str(e)}", 500
